Analyze this Node.js Transform stream for correctness:

const { Transform } = require('stream');

class CSVToJSON extends Transform {
  constructor() {
    super({ readableObjectMode: true });
    this.headers = null;
    this.buffer = '';
  }
  _transform(chunk, encoding, callback) {
    this.buffer += chunk.toString();
    const lines = this.buffer.split('\n');
    this.buffer = lines.pop(); // Keep incomplete line
    for (const line of lines) {
      if (!this.headers) {
        this.headers = line.split(',');
      } else {
        const values = line.split(',');
        const obj = {};
        this.headers.forEach((h, i) => obj[h.trim()] = values[i]?.trim());
        this.push(obj);
      }
    }
    callback();
  }
  _flush(callback) {
    if (this.buffer && this.headers) {
      const values = this.buffer.split(',');
      const obj = {};
      this.headers.forEach((h, i) => obj[h.trim()] = values[i]?.trim());
      this.push(obj);
    }
    callback();
  }
}

Step 1: Why is readableObjectMode: true needed?
Step 2: Why does _transform keep lines.pop() in buffer?
Step 3: What is _flush for?

